 1→import React from 'react';
 2→import {StatusBar, StyleSheet, Text, View} from 'react-native';
 3→import {GestureHandlerRootView} from 'react-native-gesture-handler';
 4→import {SafeAreaProvider} from 'react-native-safe-area-context';
 5→import {QueryClientProvider} from '@tanstack/react-query';
 6→import {RootNavigator} from './src/navigation/RootNavigator';
 7→import {queryClient} from './src/lib/queryClient';
 8→import * as authProviderModule from './src/features/auth/AuthProvider';
 9→import {AppErrorBoundary} from './src/components/AppErrorBoundary';
10→import {ThemeProvider, useTheme} from './src/theme/ThemeProvider';
11→
12→function AppContent(): React.JSX.Element {
13→  const {colors, isDark} = useTheme();
14→
15→  const AuthProvider = authProviderModule.AuthProvider as
16→    | React.ComponentType<{children: React.ReactNode}>
17→    | undefined;
18→
19→  if (!AuthProvider) {
20→    return (
21→      <View style={[styles.errorContainer, {backgroundColor: colors.bgPrimary}]}>
22→        <Text style={[styles.errorTitle, {color: colors.textPrimary}]}>
23→          Auth module failed to load
24→        </Text>
25→        <Text style={[styles.errorBody, {color: colors.textMuted}]}>
26→          Restart Metro with --reset-cache and relaunch the app.
27→        </Text>
28→      </View>
29→    );
30→  }
31→
32→  return (
33→    <QueryClientProvider client={queryClient}>
34→      <AuthProvider>
35→        <StatusBar
36→          barStyle={isDark ? 'light-content' : 'dark-content'}
37→          backgroundColor={colors.bgPrimary}
38→        />
39→        <RootNavigator />
40→      </AuthProvider>
41→    </QueryClientProvider>
42→  );
43→}
44→
45→function App(): React.JSX.Element {
46→  return (
47→    <GestureHandlerRootView style={styles.root}>
48→      <SafeAreaProvider>
49→        <ThemeProvider>
50→          <AppErrorBoundary>
51→            <AppContent />
52→          </AppErrorBoundary>
53→        </ThemeProvider>
54→      </SafeAreaProvider>
55→    </GestureHandlerRootView>
56→  );
57→}
58→
59→const styles = StyleSheet.create({
60→  root: {
61→    flex: 1,
62→  },
63→  errorContainer: {
64→    flex: 1,
65→    alignItems: 'center',
66→    justifyContent: 'center',
67→    paddingHorizontal: 24,
68→  },
69→  errorTitle: {
70→    fontSize: 20,
71→    fontWeight: '700',
72→    marginBottom: 12,
73→    textAlign: 'center',
74→  },
75→  errorBody: {
76→    fontSize: 15,
77→    lineHeight: 22,
78→    textAlign: 'center',
79→  },
80→});
81→
82→export default App;
