 550→app.use((req, res, next) => {
 551→    metricsState.requests += 1;
 552→    metricsState.inFlight += 1;
 553→
 554→    const startNs = process.hrtime.bigint();
 555→    let byteCount = 0;
 556→
 557→    const originalWrite = res.write.bind(res);
 558→    const originalEnd = res.end.bind(res);
 559→
 560→    res.write = (chunk, encoding, callback) => {
 561→        if (chunk) {
 562→            byteCount += Buffer.isBuffer(chunk)
 563→                ? chunk.length
 564→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 565→        }
 566→        return originalWrite(chunk, encoding, callback);
 567→    };
 568→
 569→    res.end = (chunk, encoding, callback) => {
 570→        if (chunk) {
 571→            byteCount += Buffer.isBuffer(chunk)
 572→                ? chunk.length
 573→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 574→        }
 575→        return originalEnd(chunk, encoding, callback);
 576→    };
 577→
 578→    res.on('finish', () => {
 579→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 580→        metricsState.responses += 1;
 581→        metricsState.bytesSent += byteCount;
 582→
 583→        const statusBucket = classifyStatusBucket(res.statusCode);
 584→        metricsState.statusBuckets[statusBucket] += 1;
 585→
 586→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 587→        const routeTemplate = req.route?.path
 588→            ? `${req.baseUrl || ''}${req.route.path}`
 589→            : req.path;
 590→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 591→
 592→        let routeStat = metricsState.routeStats.get(routeKey);
 593→        if (!routeStat) {
 594→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 595→                return;
 596→            }
 597→
 598→            routeStat = {
 599→                count: 0,
 600→                totalDurationMs: 0,
 601→                maxDurationMs: 0,
 602→                bytesSent: 0,
 603→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 604→            };
 605→            metricsState.routeStats.set(routeKey, routeStat);
 606→        }
 607→
 608→        routeStat.count += 1;
 609→        routeStat.totalDurationMs += durationMs;
 610→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 611→        routeStat.bytesSent += byteCount;
 612→        routeStat.statusBuckets[statusBucket] += 1;
 613→    });
 614→
 615→    next();
 616→});
