  1→import { createContext, useContext, useState, useEffect, useCallback, useMemo } from 'react';
  2→import supabase from '../utils/supabaseClient';
  3→import { useQuery, useQueryClient } from '@tanstack/react-query';
  4→import { getNotificationsCount, getUserData } from '../../API/Api';
  5→
  6→
  7→export const AuthContext = createContext();
  8→
  9→export const AuthProvider = ({children}) => {
 10→    const [loading, setLoading] = useState(true);
 11→    const [showAuthModal, setShowAuthModal] = useState(false);
 12→
 13→    const openAuthModal = useCallback(() => setShowAuthModal(true), []);
 14→    const closeAuthModal = useCallback(() => setShowAuthModal(false), []);
 15→
 16→    const queryClient = useQueryClient();
 17→
 18→    const {data: authData, isLoading: isAuthLoading} = useQuery({
 19→        queryKey: ['authsession'],
 20→        queryFn: async() =>{
 21→            const {data, error} = await supabase.auth.getSession();
 22→            if(error) throw error;
 23→            return data.session
 24→        },
 25→        staleTime: 1000 * 60 * 60,
 26→        gcTime: 1000 * 60 * 60,
 27→    })
 28→
 29→    useEffect(() =>{
 30→        let mounted = true;
 31→
 32→        if(!isAuthLoading && mounted){
 33→            setLoading(false)
 34→        }
 35→        const {data: listener} = supabase.auth.onAuthStateChange((_event, session) => {
 36→            if(mounted){
 37→                queryClient.setQueryData(['authsession'], session ?? null);
 38→                setLoading(false)
 39→            }
 40→        })
 41→        return() => {
 42→            mounted = false;
 43→            listener.subscription.unsubscribe();
 44→        }
 45→
 46→    }, [isAuthLoading, queryClient])
 47→
 48→    const {data: userData, isLoading} = useQuery({
 49→            queryKey: ['userData', authData?.user?.id],
 50→            queryFn: ({queryKey}) => getUserData(queryKey[1]),
 51→            enabled: !!authData?.access_token,
 52→            staleTime: 1000 * 60 * 60,
 53→            gcTime: 1000 * 60 * 60,
 54→        })
 55→
 56→    const {data: notifCount} = useQuery({
 57→        queryKey: ['notifcounts', authData?.user?.id],
 58→        queryFn: ({queryKey}) => getNotificationsCount(queryKey[1], authData?.access_token),
 59→        enabled: !!authData?.access_token,
 60→        staleTime: 1000 * 60 * 60,
 61→        gcTime: 1000 * 60 * 60,
 62→    })
 63→
 64→    // Combined realtime subscription for both notification tables
 65→    useEffect(() =>{
 66→        if(!userData) return;
 67→
 68→        const userId = userData?.userData?.[0]?.id;
 69→        if (!userId) return;
 70→
 71→        const handleNewNotif = () => {
 72→            queryClient.setQueryData(['notifcounts', authData?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) + 1}));
 73→        };
 74→
 75→        const channel = supabase
 76→        .channel('all-notifications')
 77→        .on('postgres_changes',
 78→            {event: 'INSERT', schema: 'public', table: 'notifications', filter: `receiver_id=eq.${userId}`},
 79→            handleNewNotif
 80→        )
 81→        .on('postgres_changes',
 82→            {event: 'INSERT', schema: 'public', table: 'notification_opinions', filter: `receiver_id=eq.${userId}`},
 83→            handleNewNotif
 84→        )
 85→        .subscribe();
 86→
 87→        return () => {
 88→            supabase.removeChannel(channel);
 89→        }
 90→
 91→    },[userData, authData?.user?.id, queryClient])
 92→
 93→
 94→    const signOut = useCallback(async() =>{
 95→        await supabase.auth.signOut({ scope: 'local' });
 96→        queryClient.setQueryData(['authsession'], null)
 97→        queryClient.clear();
 98→    }, [queryClient])
 99→
100→    const requireAuth = useCallback((callback) => {
101→        if(authData){
102→            callback();
103→        } else {
104→            openAuthModal();
105→        }
106→    }, [authData, openAuthModal])
107→
108→    const value = useMemo(() => ({
109→        session: authData,
110→        user: userData,
111→        loading: loading,
112→        isLoading: isLoading,
113→        notifCount: notifCount?.count,
114→        signOut,
115→        showAuthModal,
116→        openAuthModal,
117→        closeAuthModal,
118→        requireAuth
119→    }), [authData, userData, loading, isLoading, notifCount?.count, signOut, showAuthModal, openAuthModal, closeAuthModal, requireAuth])
120→
121→    return <AuthContext.Provider value={value}>
122→        {children}
123→    </AuthContext.Provider>
124→}
