 38→export const addOpinionController = asyncHandler(async (req, res) => {
 39→    const { opinion } = req.body;
 40→    if (!opinion || opinion.length > 280) {
 41→        return res.status(400).json({ error: 'no opinion or opinion is over 280 characters' });
 42→    }
 43→    const userId = req.userId;
 44→
 45→    const { data: insertedOpinion, error } = await supabase
 46→        .from('opinions')
 47→        .insert({ user_id: userId, opinion })
 48→        .select('id')
 49→        .single();
 50→
 51→    if (error) {
 52→        console.error('supabase error:', error.message);
 53→        return res.status(500).json({ error: 'supabase error' });
 54→    }
 55→
 56→    // Non-fatal: send @mention notifications
 57→    try {
 58→        const mentionMatches = opinion.match(/@([\w-]+)/g);
 59→        if (mentionMatches && mentionMatches.length > 0) {
 60→            const usernames = [...new Set(mentionMatches.map(m => m.slice(1)))].slice(0, 10);
 61→            const { data: mentionedUsers } = await supabase
 62→                .from('users')
 63→                .select('id, username')
 64→                .in('username', usernames);
 65→            if (mentionedUsers && mentionedUsers.length > 0) {
 66→                const notifs = mentionedUsers
 67→                    .filter(u => u.id !== userId)
 68→                    .map(u => ({
 69→                        sender_id: userId,
 70→                        receiver_id: u.id,
 71→                        opinion_id: insertedOpinion.id,
 72→                        type: 'mention',
 73→                        read: false,
 74→                    }));
 75→                if (notifs.length > 0) {
 76→                    await supabase.from('notification_opinions').insert(notifs);
 77→                }
 78→            }
 79→        }
 80→    } catch (mentionErr) {
 81→        console.error('non-fatal: opinion mention notification error', mentionErr?.message);
 82→    }
 83→
 84→    // Non-fatal: record publish for writing streak
 85→    try {
 86→        recordPublishForStreak(userId).catch(err =>
 87→            console.error('non-fatal: streak record failed:', err?.message || err)
 88→        );
 89→    } catch (streakErr) {
 90→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
 91→    }
 92→
 93→    return res.status(200).json({ message: 'success' });
 94→});
