const normalizeApiPath = (path = '') => (
    String(path).startsWith('/api/')
        ? String(path).slice(4)
        : String(path)
);

const canonicalizeMetricsPath = (rawPath = '') => {
    const normalized = normalizeApiPath(rawPath);
    return normalized
        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
        .replace(/\/\d+(?=\/|$)/g, '/:id');
};

