 48→const getHotScore = (journal: JournalItem): number => {
 49→  if (typeof journal.hot_score === 'number') return journal.hot_score;
 50→  const likes = resolveCount(journal.like_count, journal.likes_count);
 51→  const comments = resolveCount(journal.comment_count, journal.comments_count);
 52→  const bookmarks = resolveCount(journal.bookmark_count);
 53→  return likes + comments * 2 + bookmarks * 3;
 54→};
