 44→  streak,
 45→  email,
 46→  onEditProfile,
 47→  onSettingsPress,
 48→  onFollowersPress,
 49→  onFollowingPress,
 50→  actionButton,
 51→}: ProfileHeroProps) {
 52→  const {colors} = useTheme();
 53→  const bgColor = profile?.profile_layout?.backgroundColor ?? colors.accentAmber;
 54→
 55→  const parsedBg = useMemo(
 56→    () => parseProfileBackground(profile?.background),
 57→    [profile?.background],
 58→  );
 59→
 60→  const fontColor = profile?.profile_font_color || null;
 61→  const nameColor = fontColor || colors.textHeading;
 62→  const mutedColor = fontColor ? `${fontColor}99` : colors.textMuted;
 63→  const secondaryColor = fontColor ? `${fontColor}CC` : colors.textSecondary;
 64→  const iconColor = fontColor ? `${fontColor}CC` : 'rgba(255,255,255,0.8)';
 65→  const shareIconColor = fontColor ? `${fontColor}CC` : colors.textSecondary;
 66→
 67→  const onShareProfile = async () => {
 68→    const username = profile?.username || profile?.name || 'user';
 69→    try {
 70→      await Share.share({
 71→        message: `Check out @${username} on iskrib!\nhttps://iskrib.com/${username}`,
 72→      });
 73→    } catch {
 74→      // User cancelled
 75→    }
 76→  };
 77→
 78→  return (
 79→    <View>
 80→      {/* Background header */}
 81→      {parsedBg.type === 'gradient' ? (
 82→        <LinearGradient
 83→          colors={parsedBg.colors}
 84→          locations={parsedBg.locations}
 85→          {...cssAngleToGradientPoints(parsedBg.angle)}
 86→          style={styles.headerBg}>
 87→          {onSettingsPress && (
 88→            <Pressable
 89→              style={styles.settingsBtn}
 90→              onPress={onSettingsPress}
 91→              hitSlop={12}>
 92→              <SettingsIcon size={22} color={iconColor} />
 93→            </Pressable>
 94→          )}
 95→        </LinearGradient>
