import React, {useMemo, useRef, useState} from 'react';
import {Alert, StyleSheet, Text, TextInput} from 'react-native';
import {useMutation} from '@tanstack/react-query';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {actions, RichEditor, RichToolbar} from 'react-native-pell-rich-editor';
import {PrimaryButton} from '../../components/PrimaryButton';
import {Screen} from '../../components/Screen';
import {useAuth} from '../../features/auth/AuthProvider';
import {mobileApi} from '../../lib/api/mobileApi';
import {queryClient} from '../../lib/queryClient';
import {useTheme} from '../../theme/ThemeProvider';
import type {RootStackParamList} from '../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'JournalEditor'>;

const stripHtml = (html: string): string => {
  return html
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
};

export function JournalEditorScreen({navigation}: Props) {
  const {colors} = useTheme();
  const {session} = useAuth();
  const editorRef = useRef<RichEditor>(null);
  const [title, setTitle] = useState('');
  const [html, setHtml] = useState('');

  const richEditorStyle = {
    backgroundColor: colors.bgElevated,
    color: colors.textPrimary,
    caretColor: colors.accentAmber,
    contentCSSText: 'font-size: 16px; line-height: 1.5;',
  };

  const canSave = useMemo(
    () => title.trim().length > 0 && stripHtml(html).length > 0,
    [html, title],
  );

  const saveMutation = useMutation({
    mutationFn: async () => {
      const token = session?.access_token;
      if (!token) {
        throw new Error('Authentication token missing');
      }

      return mobileApi.saveJournal(token, {
        title: title.trim(),
        plainText: stripHtml(html),
        html,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({queryKey: ['feed']});
      Alert.alert('Saved', 'Journal created successfully.');
      navigation.goBack();
    },
    onError: error => {
      Alert.alert(
        'Save failed',
        error instanceof Error ? error.message : 'Unknown error',
      );
    },
  });

  return (
    <Screen>
      <Text style={[styles.title, {color: colors.textPrimary}]}>Write Journal</Text>

      <TextInput
        placeholder="Title"
        placeholderTextColor={colors.textMuted}
        value={title}
        onChangeText={setTitle}
        style={[
          styles.input,
          {
            borderColor: colors.borderLight,
            backgroundColor: colors.bgElevated,
            color: colors.textPrimary,
          },
        ]}
      />

      <RichEditor
        ref={editorRef}
        style={[
          styles.editor,
          {borderColor: colors.borderLight, backgroundColor: colors.bgElevated},
        ]}
        placeholder="Write your thoughts..."
        initialHeight={220}
        onChange={setHtml}
        editorStyle={richEditorStyle}
      />

      <RichToolbar
        editor={editorRef}
        actions={[
          actions.setBold,
          actions.setItalic,
          actions.setUnderline,
          actions.insertBulletsList,
          actions.insertOrderedList,
        ]}
        selectedIconTint={colors.accentAmber}
        iconTint={colors.textMuted}
        style={[
          styles.toolbar,
          {borderColor: colors.borderLight, backgroundColor: colors.bgSecondary},
        ]}
      />

      <PrimaryButton
        label="Save Journal"
        onPress={() => saveMutation.mutate()}
        loading={saveMutation.isPending}
        disabled={!canSave}
      />
    </Screen>
  );
}

const styles = StyleSheet.create({
  title: {
    fontSize: 24,
    fontWeight: '800',
  },
  input: {
    borderWidth: 1,
    borderRadius: 10,
    paddingHorizontal: 12,
    paddingVertical: 10,
  },
  editor: {
    borderWidth: 1,
    borderRadius: 12,
    minHeight: 220,
  },
  toolbar: {
    borderRadius: 10,
    borderWidth: 1,
  },
});

